def validate_saml_request(saml_request):
    if not saml_request or len(saml_request) > MAX_REQUEST_SIZE:
        return False
    
    try:
        decoded = base64.b64decode(saml_request)
        if len(decoded) > MAX_REQUEST_SIZE:
            return False
        
        root = etree.fromstring(decoded)
        
        if root.tag not in ['{urn:oasis:names:tc:SAML:2.0:protocol}AuthnRequest']:
            return False
        
        return True
    except Exception:
        return False

def validate_sp_configuration(acs_url):
    if not acs_url:
        return None
    
    if not acs_url.startswith('https://'):
        return None
    
    return ALLOWED_SERVICE_PROVIDERS.get(acs_url)

def authenticate_user(username, password):
    if not username or not password:
        return None
    
    if len(username) > 255 or len(password) > 255:
        return None
    
    allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@._-')
    if not all(c in allowed_chars for c in username):
        return None
    
    user_db = {
        'user1@example.com': {
            'password_hash': 'hashed_password_1',
            'attributes': {
                'email': 'user1@example.com',
                'firstName': 'User',
                'lastName': 'One',
                'role': 'employee'
            }
        }
    }
    
    user = user_db.get(username)
    if user and user['password_hash'] == f'hashed_{password}':
        return user['attributes']
    
    return None

def create_saml_response(user_attributes, sp_config, in_response_to=None):
    issue_instant = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_before = datetime.utcnow().strftime('%Y-%m-%dT%H:%M:%SZ')
    not_on_or_after = (datetime.utcnow() + timedelta(minutes=5)).strftime('%Y-%m-%dT%H:%M:%SZ')
    
    response_id = f'_response_{uuid.uuid4().hex}'
    assertion_id = f'_assertion_{uuid.uuid4().hex}'
    
    saml_response = f'''<samlp:Response xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
                         xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                         ID="{response_id}"
                         Version="2.0"
                         IssueInstant="{issue_instant}"
                         Destination="{sp_config['acs_url']}"'''
    
    if in_response_to:
        saml_response += f' InResponseTo="{in_response_to}"'
    
    saml_response += f'''>
    <saml:Issuer>https://idp.internal.example.com</saml:Issuer>
    <samlp:Status>
        <samlp:StatusCode Value="urn:oasis:names:tc:SAML:2.0:status:Success"/>
    </samlp:Status>
    <saml:Assertion xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
                    ID="{assertion_id}"
                    Version="2.0"
                    IssueInstant="{issue_instant}">
        <saml:Issuer>https://idp.internal.example.com</saml:Issuer>
        <saml:Subject>
            <saml:NameID Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress">{user_attributes.get('email', '')}</saml:NameID>
            <saml:SubjectConfirmation Method="urn:oasis:names:tc:SAML:2.0:cm:bearer">
                <saml:SubjectConfirmationData NotOnOrAfter="{not_on_or_after}"
                                              Recipient="{sp_config['acs_url']}"'''
    
    if in_response_to:
        saml_response += f' InResponseTo="{in_response_to}"'
    
    saml_response += f'''/>
            </saml:SubjectConfirmation>
        </saml:Subject>
        <saml:Conditions NotBefore="{not_before}" NotOnOrAfter="{not_on_or_after}">
            <saml:AudienceRestriction>
                <saml:Audience>{sp_config['audience']}</saml:Audience>
            </saml:AudienceRestriction>
        </saml:Conditions>
        <saml:AuthnStatement AuthnInstant="{issue_instant}" SessionIndex="{uuid.uuid4().hex}">
            <saml:AuthnContext>
                <saml:AuthnContextClassRef>urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport</saml:AuthnContextClassRef>
            </saml:AuthnContext>
        </saml:AuthnStatement>
        <saml:AttributeStatement>'''
    
    for attr_name, attr_value in user_attributes.items():
        safe_value = str(attr_value).replace('&', '&amp;').replace('<', '&lt;').replace('>', '&gt;').replace('"', '&quot;')
        saml_response += f'''
            <saml:Attribute Name="{attr_name}">
                <saml:AttributeValue>{safe_value}</saml:AttributeValue>
            </saml:Attribute>'''
    
    saml_response += '''
        </saml:AttributeStatement>
    </saml:Assertion>
</samlp:Response>'''
    
    signed_response = sign_saml_assertion(saml_response)
    
    return base64.b64encode(signed_response.encode('utf-8')).decode('utf-8')

def sign_saml_assertion(saml_response):
    root = etree.fromstring(saml_response.encode('utf-8'))
    
    assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
    
    if assertion is not None:
        signed_assertion = OneLogin_Saml2_Utils.add_sign(
            etree.tostring(assertion, encoding='unicode'),
            key_manager.get_private_key_pem(),
            key_manager.get_certificate_pem(),
            sign_algorithm=OneLogin_Saml2_Constants.RSA_SHA256
        )
        
        signed_assertion_element = etree.fromstring(signed_assertion.encode('utf-8'))
        
        parent = assertion.getparent()
        parent.replace(assertion, signed_assertion_element)
    
    return etree.tostring(root, encoding='unicode')

