@app.route('/sso', methods=['POST'])
def sso():
    if not request.is_secure:
        abort(403)
    
    username = request.form.get('username', '')
    password = request.form.get('password', '')
    relay_state = request.form.get('RelayState', '')
    saml_request = request.form.get('SAMLRequest', '')
    
    if relay_state and len(relay_state) > 1000:
        abort(400)
    
    if saml_request and not validate_saml_request(saml_request):
        abort(400)
    
    user_attributes = authenticate_user(username, password)
    if not user_attributes:
        abort(401)
    
    acs_url = request.form.get('acs_url', '')
    sp_config = validate_sp_configuration(acs_url)
    
    if not sp_config:
        abort(400)
    
    in_response_to = None
    if saml_request:
        try:
            decoded = base64.b64decode(saml_request)
            root = etree.fromstring(decoded)
            in_response_to = root.get('ID')
        except Exception:
            pass
    
    saml_response = create_saml_response(user_attributes, sp_config, in_response_to)
    
    return jsonify({
        'SAMLResponse': saml_response,
        'RelayState': relay_state,
        'ACS_URL': sp_config['acs_url']
    })

